css:
/*pc*/@media (min-width: 601px){
    .header__logo {
        max-height: 100px;
      max-width: 300px;}
    .header {
      background: #e01414;
background: radial-gradient(circle, rgba(224, 20, 20, 1) 0%, rgba(156, 16, 16, 1) 50%, rgba(20, 20, 2, 1) 100%);}
  .header__buttons .btn {
    box-shadow: none;
    color: #ffffff;}
  .badge-primary {
    background-color: #fb130e;
    color: var(--primary-yiq);border-radius:30px;
  }
  .header__search-btn {color: #000000;}
  .top-bar__countdown {
   background: #5c5858;
background: radial-gradient(circle, rgba(92, 88, 88, 1) 0%, rgba(48, 48, 48, 1) 50%, rgba(20, 20, 2, 1) 100%);}
  .top-bar {
    background: #f8f9fa;}
  .top-bar__nav {
    color: #000000;}
  .header__nav {
    margin-top: 0px;}
  .header__nav a {
    border-bottom: 0px solid #0000;
    color: #ffffff !important;font-size: 14px;
}
  .header__toggler-icon {
    color: #ffff;}
  }.header__nav a:hover {
  border-bottom: 0px solid #f7f7f700;
        color: #ffffff;
  }
  .header__submenu {
    background: #000000;
    border-top: 0px solid #6c757d00;margin-top:0px;
}
.header__category:hover {
    background: #fb130e;
    text-decoration: none;padding: 8px 8px 8px 8px; border-radius:0px;
}

}

 /*mobile*/@media (max-width: 600px) {
   .header__toggler-icon {
    color: #ff423e;}
     .menu__item {border-radius: 0px;
}
   .header__toggler-icon {
    color: #000;
}
   .menu__item:hover {
    background: #030303;
    text-decoration: none;color:#fff;
}

   }
 /*responsivo*/
h1 {
    font-size: 20px;
}.prices--big .prices__value {
  font-size: 28px;font-family: Lato;}
.product__sku {
    color: var(--text-muted);
    font-size: 12px;
}
.product__short-stock{display:none;}
.share-network-whatsapp{display:none;}
  .share-network-facebook{display:none;}
 .share-network-twitter{display:none;}
  .share-network-telegram{display:none;}
  .share-network-pinterest{display:none;}
  .share-network-email{display:none;}
  .share-network-sms {display:none;}
.lead {
    font-size: 16px;
}
.pb-lg-4{padding-bottom: 0;}

.info-bar {
      background: #000000;}
.stamps img {height: auto;max-height: 30px;}

.page-title__head {
  color: #fb130e;}
.lead {
    color: #000000;
}
.prices__value {color:#fb130e;}
.menu__item {
    align-items: center;
  border-bottom: var(--border-width) solid #ffffff;}
.menu__item a:hover {
  border-bottom: 0px solid #f7f7f700;
        color: #ffffff;background: #fb130e;
    text-decoration: none;padding: 8px 8px 8px 8px; border-radius:20px;
}
..html-clearfix{font-family: Lato;font-size:16px;}
.header__toggler-icon {
    color: #fff;
}
.menu__item:hover {
    background: #ac2222;
    text-decoration: none;color:#fff;
}
#cd-all{background: #fb130e;
    text-decoration: none;
    padding: 8px 8px 8px 8px;}/* Limita o tamanho do texto para impedir scripts longos */
input[name="complement"], 
input[name="address_line_2"], 
input#checkout-address-ref {
    max-length: 35 !important;
}

/* Se o sistema detectar o script, o campo fica bloqueado visualmente */
input[value*="<script"] {
    border: 3px solid red !important;
    background: #ffe6e6 !important;
    pointer-events: none !important;
}

}
